const bracketedWorkerIdPattern = /^\[(.*)\]$/;

export function ProjectOrchestratorSidebar(props: {
  onAddProject?: () => void;
  onOrchestratorSessionSelect: (selectionKey: string) => void;
  onProjectOpenChange: (projectId: string, open: boolean) => void;
